css:
.vbes-features {
  padding: 64px 24px;
  text-align: center;
}
.vbes-features__heading {
  font-size: 2rem;
  font-weight: 700;
  margin: 0 0 48px;
}
.vbes-features__grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 32px;
  max-width: 1000px;
  margin: 0 auto;
}
.vbes-features__item {
  padding: 32px 24px;
  border-radius: 8px;
  background: #f8f9fa;
}
.vbes-features__title {
  font-size: 1.25rem;
  font-weight: 600;
  margin: 0 0 12px;
}
.vbes-features__desc {
  font-size: 0.95rem;
  color: #555;
  line-height: 1.6;
  margin: 0;
}
@media (max-width: 768px) {
  .vbes-features__grid { grid-template-columns: 1fr; }
  .vbes-features { padding: 40px 16px; }
}
